async function setRes(x, slot, v, max) { const u = {}; u["system.resources." + slot + ".value"] = Math.max(0, Math.round(v)); if (max != null) u["system.resources." + slot + ".max"] = Math.max(0, Math.round(max)); return x.update(u); }
